components.SendMoneyFlow:
export default function SendMoneyFlow() {
  const [payees, setPayees] = useState([]);
  const [accounts, setAccounts] = useState([]);
  const [step, setStep] = useState("compose"); // compose | review | awaiting | done
  const [payeeId, setPayeeId] = useState("");
  const [amountDollars, setAmountDollars] = useState("");
  const [memo, setMemo] = useState("");
  const [error, setError] = useState("");
  const [result, setResult] = useState(null);

  useEffect(() => {
    tools.host_listPayees({}).then((r) => setPayees(r.data ?? r));
    tools.host_listAccounts({}).then((r) => setAccounts(r.data ?? r));
  }, []);

  const checking = accounts.find((a) =>
    (a.type ?? a.accountType ?? "").toLowerCase().includes("check") ||
    (a.name ?? "").toLowerCase().includes("check")
  ) ?? accounts[0];

  const selectedPayee = payees.find((p) => String(p.id) === String(payeeId));
  const amountCents = Math.round(parseFloat(amountDollars) * 100);
  const valid = selectedPayee && amountDollars && !isNaN(amountCents) && amountCents > 0;

  const handleReview = () => {
    setError("");
    if (!selectedPayee) { setError("Please select a payee."); return; }
    if (!amountDollars || isNaN(amountCents) || amountCents <= 0) { setError("Please enter a valid amount."); return; }
    setStep("review");
  };

  const handleSend = async () => {
    setStep("awaiting");
    try {
      const res = await tools.host_transferMoney({
        amount: amountCents,
        recipient_name: selectedPayee.name,
        memo: memo || undefined,
      });
      setResult(res);
      setStep("done");
    } catch (e) {
      setError("Something went wrong. Please try again.");
      setStep("review");
    }
  };

  const reset = () => {
    setStep("compose");
    setPayeeId("");
    setAmountDollars("");
    setMemo("");
    setError("");
    setResult(null);
  };

  const labelStyle = {
    display: "block",
    fontSize: "13px",
    color: "var(--vendo-color-muted)",
    marginBottom: "6px",
    fontFamily: "var(--vendo-font-family)",
  };
  const inputStyle = {
    width: "100%",
    boxSizing: "border-box",
    padding: "10px 12px",
    fontSize: "15px",
    fontFamily: "var(--vendo-font-family)",
    border: "1px solid var(--vendo-color-border)",
    borderRadius: "var(--vendo-radius-small)",
    background: "var(--vendo-color-surface)",
    color: "var(--vendo-color-text)",
    outline: "none",
  };
  const fieldStyle = { display: "grid", gap: "6px" };
  const btnPrimary = {
    padding: "12px 24px",
    background: "var(--vendo-color-accent)",
    color: "var(--vendo-color-accent-text)",
    border: "none",
    borderRadius: "var(--vendo-radius-small)",
    fontSize: "15px",
    fontFamily: "var(--vendo-font-family)",
    fontWeight: 600,
    cursor: "pointer",
    width: "100%",
  };
  const btnSecondary = {
    padding: "12px 24px",
    background: "transparent",
    color: "var(--vendo-color-text)",
    border: "1px solid var(--vendo-color-border)",
    borderRadius: "var(--vendo-radius-small)",
    fontSize: "15px",
    fontFamily: "var(--vendo-font-family)",
    fontWeight: 500,
    cursor: "pointer",
    width: "100%",
  };
  const surface = {
    background: "var(--vendo-color-surface)",
    border: "1px solid var(--vendo-color-border)",
    borderRadius: "var(--vendo-radius-medium)",
    padding: "28px 24px",
    display: "grid",
    gap: "20px",
    maxWidth: "480px",
    margin: "0 auto",
    fontFamily: "var(--vendo-font-family)",
  };
  const rowStyle = { display: "grid", gridTemplateColumns: "1fr 1fr", gap: "12px" };
  const divider = { borderTop: "1px solid var(--vendo-color-border)", margin: "4px 0" };
  const reviewRow = { display: "flex", justifyContent: "space-between", alignItems: "center", padding: "6px 0" };
  const reviewLabel = { fontSize: "14px", color: "var(--vendo-color-muted)" };
  const reviewValue = { fontSize: "15px", color: "var(--vendo-color-text)", fontWeight: 500 };

  if (step === "compose") {
    return (
      <div style={surface}>
        <div>
          <div style={{ fontSize: "20px", fontWeight: 700, color: "var(--vendo-color-text)", marginBottom: "4px" }}>Send money</div>
          <div style={{ fontSize: "14px", color: "var(--vendo-color-muted)" }}>
            From {checking ? (checking.name ?? "Checking") : "your checking account"}
            {checking?.balanceCents != null ? ` · ${fmt.money(checking.balanceCents)} available` : ""}
          </div>
        </div>
        <div style={fieldStyle}>
          <label style={labelStyle}>Pay to</label>
          <select
            value={payeeId}
            onChange={(e) => setPayeeId(e.target.value)}
            style={inputStyle}
          >
            <option value="">Choose a payee…</option>
            {payees.map((p) => (
              <option key={p.id} value={p.id}>{p.name}{p.accountNumber ? ` ···${String(p.accountNumber).slice(-4)}` : ""}</option>
            ))}
          </select>
        </div>
        <div style={fieldStyle}>
          <label style={labelStyle}>Amount</label>
          <div style={{ position: "relative" }}>
            <span style={{ position: "absolute", left: "12px", top: "50%", transform: "translateY(-50%)", color: "var(--vendo-color-muted)", fontSize: "15px" }}>$</span>
            <input
              type="number"
              min="0.01"
              step="0.01"
              placeholder="0.00"
              value={amountDollars}
              onChange={(e) => setAmountDollars(e.target.value)}
              style={{ ...inputStyle, paddingLeft: "26px" }}
            />
          </div>
        </div>
        <div style={fieldStyle}>
          <label style={labelStyle}>Note (optional)</label>
          <textarea
            placeholder="What's this for?"
            value={memo}
            onChange={(e) => setMemo(e.target.value)}
            rows={2}
            style={{ ...inputStyle, resize: "vertical" }}
          />
        </div>
        {error && <div style={{ fontSize: "14px", color: "var(--vendo-color-danger)" }}>{error}</div>}
        <button style={{ ...btnPrimary, opacity: valid ? 1 : 0.5 }} onClick={handleReview}>
          Review transfer
        </button>
      </div>
    );
  }

  if (step === "review") {
    return (
      <div style={surface}>
        <div>
          <div style={{ fontSize: "20px", fontWeight: 700, color: "var(--vendo-color-text)", marginBottom: "4px" }}>Review transfer</div>
          <div style={{ fontSize: "14px", color: "var(--vendo-color-muted)" }}>Confirm the details before sending.</div>
        </div>
        <div style={{ background: "var(--vendo-color-background)", borderRadius: "var(--vendo-radius-small)", padding: "16px 18px", display: "grid", gap: "2px" }}>
          <div style={{ ...reviewRow, paddingBottom: "12px" }}>
            <span style={{ fontSize: "28px", fontWeight: 700, color: "var(--vendo-color-text)" }}>{fmt.money(amountCents)}</span>
          </div>
          <div style={divider}/>
          <div style={reviewRow}>
            <span style={reviewLabel}>To</span>
            <span style={reviewValue}>{selectedPayee?.name}</span>
          </div>
          <div style={reviewRow}>
            <span style={reviewLabel}>From</span>
            <span style={reviewValue}>{checking?.name ?? "Checking"}</span>
          </div>
          {memo ? (
            <div style={reviewRow}>
              <span style={reviewLabel}>Note</span>
              <span style={{ ...reviewValue, maxWidth: "60%", textAlign: "right" }}>{memo}</span>
            </div>
          ) : null}
        </div>
        <div style={{ fontSize: "13px", color: "var(--vendo-color-muted)", textAlign: "center" }}>
          This transfer is irreversible once approved.
        </div>
        {error && <div style={{ fontSize: "14px", color: "var(--vendo-color-danger)" }}>{error}</div>}
        <div style={rowStyle}>
          <button style={btnSecondary} onClick={() => setStep("compose")}>Edit</button>
          <button style={btnPrimary} onClick={handleSend}>Send money</button>
        </div>
      </div>
    );
  }

  if (step === "awaiting") {
    return (
      <div style={{ ...surface, alignItems: "center", textAlign: "center", gap: "16px" }}>
        <div style={{ fontSize: "32px" }}>⏳</div>
        <div style={{ fontSize: "18px", fontWeight: 600, color: "var(--vendo-color-text)" }}>Awaiting your approval…</div>
        <div style={{ fontSize: "14px", color: "var(--vendo-color-muted)" }}>
          Sending {fmt.money(amountCents)} to {selectedPayee?.name}. Please approve in your Maple app.
        </div>
      </div>
    );
  }

  if (step === "done") {
    return (
      <div style={{ ...surface, alignItems: "center", textAlign: "center", gap: "16px" }}>
        <div style={{ fontSize: "40px" }}>✓</div>
        <div style={{ fontSize: "20px", fontWeight: 700, color: "var(--vendo-color-text)" }}>Transfer sent</div>
        <div style={{ fontSize: "15px", color: "var(--vendo-color-muted)" }}>
          {fmt.money(amountCents)} sent to {selectedPayee?.name}.
          {memo ? ` "${memo}"` : ""}
        </div>
        <button style={{ ...btnSecondary, marginTop: "8px" }} onClick={reset}>Send another</button>
      </div>
    );
  }

  return null;
}
